{"type":"user","message":{"role":"user","content":[{"tool_use_id":"tooluse_lm4SPn5QHAd9fbPJO8WYP4","type":"tool_result","content":"1\t#!/usr/bin/env python3\n2\t\"\"\"\n3\t52周新高突破跟进分析\n4\t找出创业板中创52周新高、量能放大且持续上涨的股票\n5\t\"\"\"\n6\t\n7\timport akshare as ak\n8\timport pandas as pd\n9\tfrom datetime import datetime, timedelta\n10\timport warnings\n11\twarnings.filterwarnings('ignore')\n12\t\n13\tdef get_chinext_stocks():\n14\t    \"\"\"获取创业板股票列表\"\"\"\n15\t    try:\n16\t        stock_info = ak.stock_info_a_code_name()\n17\t        chinext = stock_info[stock_info['code'].str.startswith('300')]\n18\t        return chinext['code'].tolist()\n19\t    except Exception as e:\n20\t        print(f\"获取创业板股票列表失败: {e}\")\n21\t        return []\n22\t\n23\tdef get_stock_data(stock_code, end_date='2024-11-15'):\n24\t    \"\"\"\n25\t    获取股票历史数据\n26\t    需要至少 252 + 30 + 5 = 287 个交易日的数据\n27\t    \"\"\"\n28\t    try:\n29\t        # 获取更多数据以确保有足够的交易日\n30\t        start_date = '2023-06-01'  # 提前足够时间\n31\t        df = ak.stock_zh_a_hist(symbol=stock_code, period=\"daily\", \n32\t                                start_date=start_date, end_date=end_date, adjust=\"qfq\")\n33\t        \n34\t        if df is None or len(df) == 0:\n35\t            return None\n36\t            \n37\t        # 重命名列\n38\t        df = df.rename(columns={\n39\t            '日期': 'date',\n40\t            '收盘': 'close',\n41\t            '成交量': 'volume'\n42\t        })\n43\t        \n44\t        df['date'] = pd.to_datetime(df['date'])\n45\t        df = df.sort_values('date')\n46\t        df = df[['date', 'close', 'volume']].reset_index(drop=True)\n47\t        \n48\t        return df\n49\t    except Exception as e:\n50\t        print(f\"获取 {stock_code} 数据失败: {e}\")\n51\t        return None\n52\t\n53\tdef find_52week_high_breakout(df, end_date='2024-11-15'):\n54\t    \"\"\"\n55\t    在最近30个交易日内找到首次突破52周(252个交易日)新高的日期\n56\t    \n57\t    返回: (breakout_date, breakout_price, breakout_idx) 或 None\n58\t    \"\"\"\n59\t    end_date = pd.to_datetime(end_date)\n60\t    \n61\t    # 确保有足够数据\n62\t    if len(df) < 282:  # 252 + 30\n63\t        return None\n64\t    \n65\t    # 找到截止日期的索引\n66\t    df_before_end = df[df['date'] <= end_date]\n67\t    if len(df_before_end) < 282:\n68\t        return None\n69\t    \n70\t    # 最近30个交易日的窗口\n71\t    recent_30_days = df_before_end.tail(30).copy()\n72\t    \n73\t    for i in range(len(recent_30_days)):\n74\t        current_idx = len(df_before_end) - len(recent_30_days) + i\n75\t        current_date = df_before_end.iloc[current_idx]['date']\n76\t        current_close = df_before_end.iloc[current_idx]['close']\n77\t        \n78\t        # 获取过去252个交易日的数据（不包括当天）\n79\t        if current_idx < 252:\n80\t            continue\n81\t            \n82\t        past_252_days = df_before_end.iloc[current_idx-252:current_idx]\n83\t        max_close_252 = past_252_days['close'].max()\n84\t        \n85\t        # 检查是否创新高\n86\t        if current_close > max_close_252:\n87\t            return (current_date, current_close, current_idx)\n88\t    \n89\t    return None\n90\t\n91\tdef check_volume_confirmation(df, breakout_idx):\n92\t    \"\"\"\n93\t    检查量能确认：创新高日±2天(共5天)的成交量均值 > 60日均量的1.5倍\n94\t    \"\"\"\n95\t    # 5天窗口：breakout_idx-2 到 breakout_idx+2\n96\t    window_start = max(0, breakout_idx - 2)\n97\t    window_end = min(len(df), breakout_idx + 3)  # +3 因为是左闭右开\n98\t    \n99\t    if window_end - window_start < 5:\n100\t        return False\n101\t    \n102\t    volume_window = df.iloc[window_start:window_end]['volume']\n103\t    avg_volume_window = volume_window.mean()\n104\t    \n105\t    # 60日均量（在突破日之前）\n106\t    if breakout_idx < 60:\n107\t        return False\n108\t    \n109\t    past_60_days = df.iloc[breakout_idx-60:breakout_idx]\n110\t    avg_volume_60 = past_60_days['volume'].mean()\n111\t    \n112\t    return avg_volume_window > (avg_volume_60 * 1.5)\n113\t\n114\tdef check_followthrough(df, breakout_idx, breakout_price):\n115\t    \"\"\"\n116\t    检查持续性：新高后5个交易日内，至少3天收盘价