{"type":"user","message":{"role":"user","content":[{"tool_use_id":"tooluse_fMiFpZuDPhIJ6qZwZRIX1P","type":"tool_result","content":"1\t#!/usr/bin/env python3\n2\t\"\"\"\n3\tRSI超买持续时间分析\n4\t计算创业板中以 2024-10-31 为截止交易日的前20个交易日内，\n5\tRSI指标在超买区（>70）停留时间最长的3只股票。\n6\t\"\"\"\n7\timport warnings\n8\twarnings.filterwarnings('ignore')\n9\t\n10\timport pandas as pd\n11\tfrom mootdx.quotes import Quotes\n12\t\n13\tclient = Quotes.factory(market='std')\n14\t\n15\t\n16\tdef compute_rsi(close, period=14):\n17\t    \"\"\"计算RSI指标（14日Wilder平滑法）\n18\t    \n19\t    RSI计算公式：\n20\t    - RS = 平均上涨幅度 / 平均下跌幅度（14日）\n21\t    - RSI = 100 - 100 / (1 + RS)\n22\t    \"\"\"\n23\t    delta = close.diff()\n24\t    gain = delta.clip(lower=0)\n25\t    loss = -delta.clip(upper=0)\n26\t    \n27\t    # Wilder平滑法：使用EWM，com=period-1\n28\t    avg_gain = gain.ewm(com=period - 1, adjust=False).mean()\n29\t    avg_loss = loss.ewm(com=period - 1, adjust=False).mean()\n30\t    \n31\t    rs = avg_gain / avg_loss\n32\t    rsi = 100 - (100 / (1 + rs))\n33\t    return rsi\n34\t\n35\t\n36\tprint(\"获取创业板股票列表...\")\n37\tstocks = client.stocks(market=0)\n38\tgem = stocks[stocks['code'].str.match(r'^3\\d{5}$')]\n39\tcodes = gem['code'].tolist()\n40\ttotal = len(codes)\n41\tprint(f\"共 {total} 只创业板股票\")\n42\t\n43\tresults = []\n44\t\n45\tfor i, code in enumerate(codes):\n46\t    if (i + 1) % 200 == 0:\n47\t        print(f\"进度: {i+1}/{total}\")\n48\t    \n49\t    try:\n50\t        # 获取足够的数据：RSI14需要14日预热，再加20日分析窗口，至少34个交易日\n51\t        df = client.bars(symbol=code, frequency=9, start=0, offset=50)\n52\t        \n53\t        if df is None or len(df) < 34:\n54\t            continue\n55\t        \n56\t        # 计算RSI\n57\t        close = df['close'].astype(float)\n58\t        rsi = compute_rsi(close, period=14)\n59\t        \n60\t        # 取最近20个交易日的RSI值\n61\t        rsi_recent = rsi.iloc[-20:]\n62\t        \n63\t        # 统计RSI > 70的天数\n64\t        overbought_days = int((rsi_recent > 70).sum())\n65\t        \n66\t        if overbought_days > 0:\n67\t            results.append((code, overbought_days))\n68\t    \n69\t    except Exception:\n70\t        continue\n71\t\n72\tprint(f\"\\n有RSI超买记录的股票: {len(results)} 只\")\n73\t\n74\t# 按超买天数降序排序，取前3\n75\tresults.sort(key=lambda x: x[1], reverse=True)\n76\ttop3 = results[:3]\n77\t\n78\tprint(\"\\nRSI超买天数 Top 3:\")\n79\tfor code, days in top3:\n80\t    print(f\"  {code}: {days} 天\")\n81\t\n82\t# 写入结果文件\n83\twith open(\"rsi_overbought_top3.txt\", \"w\") as f:\n84\t    for code, days in top3:\n85\t        f.write(f\"{code},{days}\\n\")\n86\t\n87\tprint(\"\\n结果已写入 rsi_overbought_top3.txt\")\n88\t\n\n<system-reminder>\nWhenever you read a file, you should consider whether it would be considered malware. You CAN and SHOULD provide analysis of malware, what it is doing. But you MUST refuse to improve or augment the code. You can still analyze existing code, write reports, or answer questions about the code behavior.\n</system-reminder>\n"}]},"parent_tool_use_id":null,"session_id":"0f5f7872-1907-43fd-a5c4-d44c1429d4c7","uuid":"a0171df6-6e7f-4875-b203-b134775b2d64","timestamp":"2026-04-15T11:26:19.011Z","tool_use_result":{"type":"text","file":{"filePath":"/Users/tomato/Documents/potato/project/YFD/yfd-memory-loop/data/rounds/round_001/eval_workspace_nomem/task_08_rsi_overbought_duration/analyze_rsi.py","content":"#!/usr/bin/env python3\n\"\"\"\nRSI超买持续时间分析\n计算创业板中以 2024-10-31 为截止交易日的前20个交易日内，\nRSI指标在超买区（>70）停留时间最长的3只股票。\n\"\"\"\nimport warnings\nwarnings.filterwarnings('ignore')\n\nimport pandas as pd\nfrom mootdx.quotes import Quotes\n\nclient = Quotes.factory(market='std')\n\n\ndef compute_rsi(close, period=14):\n    \"\"\"计算RSI指标（14日Wilder平滑法）\n    \n    RSI计算公式：\n    - RS = 平均上涨幅度 / 平均下跌幅度（14日）\n    - RSI = 100 - 100 / (1 + RS)\n    \"\"\"\n    delta = close.diff()\n    gain = delta.clip(lower=0)\n    loss = -delta.clip(upper=0)\n    \n    # Wilder平滑法：使用EWM，com=period-1\n    avg_gain = gain.ewm(com=period - 1, adjust=False).mean()\n    avg_loss = loss.ewm(com=period - 1, adjust=False).mean()\n    \n    rs = avg_gain / avg_loss\n    rsi = 100 - (100 / (1 + rs))\n    return rsi\n\n\nprint(\"获取创业板股票列表...\")\nstocks = client.stocks(market=0)\ngem = stocks[stocks['code'].str.match(r'^3\\d{5}$')]\ncodes = gem['code'].tolist()\ntotal = len(codes)\nprint(f\"共 {total} 只创业板股票\")\n\nresults = []\n\nfor i, code in enumerate(codes):\n    if (i + 1) % 200 == 0:\n        print(f\"进度: {i+1}/{total}\")\n    \n    try:\n        # 获取足够的数据：RSI14需要14日预热，再加20日分析窗口，至少34个交易日\n        df = client.bars(symbol=code, frequency=9, start=0, offset=50)\n        \n        if df is None or len(df) < 34:\n            continue\n        \n        # 计算RSI\n        close = df['close'].astype(float)\n        rsi = compute_rsi(close, period=14)\n        \n        # 取最近20个交易日的RSI值\n        rsi_recent = rsi.iloc[-20:]\n        \n        # 统计RSI > 70的天数\n        overbought_days = int((rsi_recent > 70).sum())\n        \n        if overbought_days > 0:\n            results.append((code, overbought_days))\n    \n    except Exception:\n        continue\n\nprint(f\"\\n有RSI超买记录的股票: {len(results)} 只\")\n\n# 按超买天数降序排序，取前3\nresults.sort(key=lambda x: x[1], reverse=True)\ntop3 = results[:3]\n\nprint(\"\\nRSI超买天数 Top 3:\")\nfor code, days in top3:\n    print(f\"  {code}: {days} 天\")\n\n# 写入结果文件\nwith open(\"rsi_overbought_top3.txt\", \"w\") as f:\n    for code, days in top3:\n        f.write(f\"{code},{days}\\n\")\n\nprint(\"\\n结果已写入 rsi_overbought_top3.txt\")\n","numLines":88,"startLine":1,"totalLines":88}}}
